function DeployStatusWidget() {
  const stages = ['Build', 'Test', 'Security Scan', 'Staging', 'Production'];
  const [current, setCurrent] = React.useState(2);
  const [status, setStatus] = React.useState('running');

  React.useEffect(() => {
    const id = setInterval(() => {
      setCurrent((c) => {
        if (status === 'success') return c;
        if (c < stages.length - 1) return c + 1;
        setStatus('success');
        return c;
      });
    }, 3000);
    return () => clearInterval(id);
  }, [status]);

  return (
    <div style={{ fontFamily: 'system-ui, sans-serif', padding: 16, background: '#0f172a', color: '#e2e8f0', borderRadius: 12, height: '100%' }}>
      <h3 style={{ margin: 0, marginBottom: 12 }}>Deploy Status</h3>
      <div style={{ fontSize: 12, color: '#94a3b8', marginBottom: 12 }}>Release: v2.4.1</div>
      <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
        {stages.map((stage, i) => {
          let icon = '○';
          let color = '#475569';
          if (i < current) { icon = '✓'; color = '#22c55e'; }
          else if (i === current) { icon = '●'; color = '#3b82f6'; }
          return (
            <div key={stage} style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
              <span style={{ color, fontWeight: 700, width: 16 }}>{icon}</span>
              <span style={{ fontSize: 13, color: i === current ? '#e2e8f0' : '#94a3b8' }}>{stage}</span>
              {i === current && status === 'running' && (
                <span style={{ fontSize: 11, color: '#3b82f6', marginLeft: 'auto' }}>In progress...</span>
              )}
            </div>
          );
        })}
      </div>
      {status === 'success' && (
        <div style={{ marginTop: 14, padding: 10, background: '#14532d', color: '#86efac', borderRadius: 8, fontSize: 13, textAlign: 'center' }}>Deployment completed successfully</div>
      )}
    </div>
  );
}
render(<DeployStatusWidget/>);
